    name: "CoQ10 / Ubiquinol",
    aliases: ["Coenzyme Q10", "Ubiquinone", "Ubiquinol", "Kaneka Ubiquinol", "Q-Sorb", "Q-Gel", "CoQH"],
    category: ["Mitochondrial", "Cardiovascular", "Longevity"],
